export type DensityLevel = 1 | 2 | 3 | 4 | 5;

export const LEVEL_MAP: Record<DensityLevel, { label: string; color: string; threshold: number; density: number }> = {
  1: { label: "1단계 (안전)", color: "#52c41a", threshold: 40, density: 0.8 },
  2: { label: "2단계 (보통)", color: "#1890ff", threshold: 80, density: 1.0 },
  3: { label: "3단계 (주의)", color: "#fadb14", threshold: 120, density: 1.4 },
  4: { label: "4단계 (혼잡)", color: "#fa8c16", threshold: 160, density: 3.3 },
  5: { label: "5단계 (위험)", color: "#ff4d4f", threshold: 161, density: 5.0 },
};

export interface DetectionArea {
  id: string;
  name: string;
  points: number[]; // [x1, y1, x2, y2...]
  color?: string;
}

export interface CameraInfo {
  id: number;
  name: string;
  hasAlarm: boolean;
  lat: number;
  lng: number;
  zoneId: string;
  siteId: string;
  floor?: string;
  crowdCount: number;
  level: DensityLevel;
  densityPerM2: number;
  x2d: number;
  y2d: number;
  imageUrl: string;
  trafficCount: number;
  trafficLevel: DensityLevel;
  entryCount: number;
  exitCount: number;
  detectionAreas?: DetectionArea[];
}

export interface ZoneInfo {
  id: string;
  name: string;
  siteId: string;
  floor?: string; // Floor 정보 추가 (B1, B2, B3, B4 등)
  totalPeople: number;
  avgLevel: DensityLevel;
  status: "NORMAL" | "CAUTION" | "WARNING" | "DANGER";
  coordinates: [number, number];
  boundary: [number, number][];
  points2D: number[]; // Flat array of [x1, y1, x2, y2...] for Konva Poly
  trafficCount: number;
  trafficLevel: DensityLevel;
  entryCount: number;
  exitCount: number;
}

export interface SiteInfo {
  id: string;
  name: string;
  location: [number, number]; // center for OSM
  zones: string[]; // zone IDs
}

export interface CrowdHistory {
  time: string;
  count: number;
  avgLevel: number;
}

// Helper to determine stage based on count
const getLevel = (count: number): DensityLevel => {
  if (count <= 40) return 1;
  if (count <= 80) return 2;
  if (count <= 120) return 3;
  if (count <= 160) return 4;
  return 5;
};

