export const MOCK_CAMERAS: CameraInfo[] = [
  ...Array.from({ length: 16 }, (_, i) => {
    const zoneIndex = Math.floor(i / 2); // 2 cameras per zone (8 zones * 2 = 16)
    const zone = MOCK_ZONES[zoneIndex];
    const count = 30 + (i % 2) * 50 + (zoneIndex * 15); 
    const lvl = getLevel(count);
    const imgList = MOCK_CROWD_IMAGES[lvl];
    const imageUrl = imgList[i % imgList.length];
    const pos = MOCK_CAMERA_2D_POS[i];
    
    // Generate split traffic data
    const trafficVal = Math.floor(count * 0.7 + Math.random() * 40);
    const entryVal = Math.floor(trafficVal * (0.4 + Math.random() * 0.2));
    const exitVal = trafficVal - entryVal;
    
    return {
      id: 100 + i,
      name: `${zone.id.split('_')[1]}-CAM-${(i % 2) + 1}`,
      hasAlarm: lvl >= 5,
      lat: zone.coordinates[0] + (Math.random() - 0.5) * 0.001,
      lng: zone.coordinates[1] + (Math.random() - 0.5) * 0.001,
      zoneId: zone.id,
      siteId: "SITE_01",
      floor: zone.floor,
      crowdCount: count,
      level: lvl,
      densityPerM2: LEVEL_MAP[lvl].density,
      x2d: pos.x,
      y2d: pos.y,
      imageUrl: imageUrl,
      trafficCount: trafficVal,
      trafficLevel: getLevel(trafficVal),
      entryCount: entryVal,
      exitCount: exitVal,
      detectionAreas: [
        { id: `area-${i}-1`, name: "검지 영역 1", points: [100, 100, 300, 100, 300, 300, 100, 300], color: "rgba(255, 0, 0, 0.3)" },
        { id: `area-${i}-2`, name: "검지 영역 2", points: [400, 100, 600, 100, 600, 300, 400, 300], color: "rgba(0, 0, 255, 0.3)" }
      ]
    };
  })
];

export const MOCK_HISTORY = (id: string, isSite: boolean = false): CrowdHistory[] => {
  const now = new Date();
  return Array.from({ length: 60 }, (_, i) => {
    const d = new Date(now.getTime() - (60 - i) * 60 * 1000); // 1-minute steps for last 60 mins
    const timeStr = `${d.getHours().toString().padStart(2, '0')}:${d.getMinutes().toString().padStart(2, '0')}`;
    const count = isSite ? 3000 + Math.floor(Math.random() * 2000) : 30 + Math.floor(Math.random() * 200);
    return {
      time: timeStr,
      count: count,
      avgLevel: isSite ? getLevel(Math.floor(count / 25)) : getLevel(count)
    };
  });
};

export const MOCK_CAMERA_HISTORY = (cameraId: number): CrowdHistory[] => {
  const now = new Date();
  return Array.from({ length: 60 }, (_, i) => {
    const d = new Date(now.getTime() - (60 - i) * 60 * 1000);
    const timeStr = `${d.getHours().toString().padStart(2, '0')}:${d.getMinutes().toString().padStart(2, '0')}`;
    return {
      time: timeStr,
      count: 20 + Math.floor(Math.random() * 180),
      avgLevel: Math.floor(Math.random() * 5) + 1
    };
  });
};
export const generateNextHistoryPoint = (isSite: boolean = false): CrowdHistory => {
  const now = new Date();
  const timeStr = `${now.getHours().toString().padStart(2, '0')}:${now.getMinutes().toString().padStart(2, '0')}`;
  
  const count = isSite ? 3000 + Math.floor(Math.random() * 2000) : 30 + Math.floor(Math.random() * 200);
  
  return {
    time: timeStr,
    count: count,
    avgLevel: isSite ? getLevel(Math.floor(count / 25)) : getLevel(count)
  };
};
